  1	import * as React from 'react';
  2	import { useTranslation } from 'react-i18next';
  3	import { EmptyState, EmptyStateVariant } from '@patternfly/react-core';
  4	import { sortable } from '@patternfly/react-table';
  5	import {
  6	  TableColumn,
  7	  VirtualizedTable,
  8	  useActiveColumns,
  9	} from '@openshift-console/dynamic-plugin-sdk';
 10	import {
 11	  SummaryProps,
 12	  sortByNumbers,
 13	  sortByProperty,
 14	  sortByTimestamp,
 15	  sortTimeStrings,
 16	  listPageTableColumnClasses as tableColumnClasses,
 17	} from '../utils';
 18	import PipelineRunsForPipelinesRow from './PipelineRunsForPipelinesRow';
 19	
 20	type PipelineRunsForPipelinesListProps = {
 21	  summaryData: SummaryProps[];
 22	  summaryDataFiltered?: SummaryProps[];
 23	  loaded: boolean;
 24	  hideLastRunTime?: boolean;
 25	};
 26	
 27	const PipelineRunsForPipelinesList: React.FC<
 28	  PipelineRunsForPipelinesListProps
 29	> = ({ summaryData, summaryDataFiltered, loaded, hideLastRunTime }) => {
 30	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 31	  const EmptyMsg = () => (
 32	    <EmptyState variant={EmptyStateVariant.lg}>
 33	      {t('No PipelineRuns found')}
 34	    </EmptyState>
 35	  );
 36	
 37	  const plrColumns = React.useMemo<TableColumn<SummaryProps>[]>(() => {
 38	    const columns: TableColumn<SummaryProps>[] = [
 39	      {
 40	        id: 'pipelineName',
 41	        title: t('Pipeline'),
 42	        sort: (summary, direction: 'asc' | 'desc') =>
 43	          sortByProperty(summary, 'pipelineName', direction),
 44	        transforms: [sortable],
 45	        props: { className: tableColumnClasses[0] },
 46	      },
 47	      {
 48	        id: 'namespace',
 49	        title: t('Project'),
 50	        sort: (summary, direction: 'asc' | 'desc') =>
 51	          sortByProperty(summary, 'namespace', direction),
 52	        transforms: [sortable],
 53	        props: { className: tableColumnClasses[1] },
 54	      },
 55	      {
 56	        id: 'total',
 57	        title: t('Total Pipelineruns'),
 58	        sort: 'total',
 59	        transforms: [sortable],
 60	        props: { className: tableColumnClasses[2] },
 61	      },
 62	      {
 63	        id: 'totalDuration',
 64	        title: t('Total duration'),
 65	        sort: (summary, direction: 'asc' | 'desc') =>
 66	          sortTimeStrings(summary, 'total_duration', direction),
 67	        transforms: [sortable],
 68	        props: { className: tableColumnClasses[3] },
 69	      },
 70	      {
 71	        id: 'avgDuration',
 72	        title: t('Average duration'),
 73	        sort: (summary, direction: 'asc' | 'desc') =>
 74	          sortTimeStrings(summary, 'avg_duration', direction),
 75	        transforms: [sortable],
 76	        props: {
 77	          className: tableColumnClasses[4],
 78	          info: {
 79	            tooltip: t(
 80	              'An average of the time taken to run PipelineRuns. The trending shown is based on the time range selected. This metric does not show runs that are running or pending.',
 81	            ),
 82	            className: 'pipeline-overview__for-pipelines-list__tooltip',
 83	          },
 84	        },
 85	      },
 86	      {
 87	        id: 'successRate',
 88	        title: t('Success rate'),
 89	        sort: (summary, direction: 'asc' | 'desc') =>
 90	          sortByNumbers(summary, 'succeeded', direction),
 91	        transforms: [sortable],
 92	        props: {
 93	          className: tableColumnClasses[5],
 94	          info: {
 95	            tooltip: t(
 96	              'Success rate measure the % of successfully completed pipeline runs in relation to the total number of pipeline runs',
 97	            ),
 98	            className: 'pipeline-overview__for-pipelines-list__tooltip',
 99	          },
100	        },
101	      },
102	    ];
103	    if (!hideLastRunTime) {
104	      columns.push({
105	        id: 'lastRunTime',
106	        title: t('Last run time'),
107	        sort: (summary, direction: 'asc' | 'desc') =>
108	          sortByTimestamp(summary, 'last_runtime', direction),
109	        transforms: [sortable],
110	        props: { className: tableColumnClasses[6] },
111	      });
112	    }
113	
114	    return columns;
115	  }, [t, hideLastRunTime]);
116	
117	  const [columns] = useActiveColumns({
118	    columns: plrColumns,
119	    showNamespaceOverride: false,
120	    columnManagementID: '',
121	  });
122	
123	  const isEmptyData =
124	    (!summaryDataFiltered || summaryDataFiltered.length === 0) &&
125	    (!summaryData || summaryData.length === 0);
126	
127	  if (loaded && isEmptyData) {
128	    return <EmptyMsg />;
129	  }
130	
131	  return (
132	    <VirtualizedTable
133	      columns={columns}
134	      Row={PipelineRunsForPipelinesRow}
135	      data={summaryDataFiltered || summaryData}
136	      loaded={loaded}
137	      loadError={false}
138	      unfilteredData={summaryData}
139	      EmptyMsg={EmptyMsg}
140	      rowData={{ hideLastRunTime }}
141	    />
142	  );
143	};
144	
145	export default PipelineRunsForPipelinesList;

